//CS, DLT, 2/20/2025 Shreelekha Samudralwar create vendor invoice journal for brokearges amount
public void active()
{
    if (ETGACFParameters::find().EnableIntercompanyTransactions==NoYes::Yes)
    {
        FormDataSource     ledgerJournalTransDS = this.dataSource();
        LedgerJournalTrans ledgerJournalTrans   = ledgerJournalTransDS.cursor();

        if (ledgerJournalTrans 
            && ledgerJournalTrans.ETGICSourceEntity
            && ledgerJournalTrans.ledgerJournalTable().Posted)
        {
            ledgerJournalTransDS.object(fieldNum(LedgerJournalTrans, AmountCurCredit)).allowEdit(false);
        }
        else
        {
            ledgerJournalTransDS.object(fieldNum(LedgerJournalTrans, AmountCurCredit)).allowEdit(true);
        }
    }
}

