/// <summary>
/// to parametrize the additional fields in delivery tab on SalesTable form
/// </summary>
public void init()
{
    boolean enable = ETGACFParameters::find().EnableAccrualSchemePostingMonthly;

    next init();

    journalFormTrans.parmCtrlETGAccrualButton(ETGLedgerJournalTransAccrual);

    LedgerJournalTransAccrual.visible(!enable);
    ETGLedgerJournalTransAccrual.visible(enable);

    if (curExt() == 'y002')
    {
        // List of all controls to hide
        container controlsToHide = [
            'LedgerJournalTrans_ETGBankAccountID',
            'LedgerJournalTrans_ETGICDestinationEntity',
            'LedgerJournalTrans_ETGCostAllocationRuleId',
            'LedgerJournalTrans_ExchRate',
            'LedgerJournalTrans_Grid_TaxItemGroup',
            'LedgerJournalTrans_Grid_TaxGroup',
            'WithHoldingTax_TaxWithholdGroup',
            'LedgerJournalTrans_ETGFairValuationSerialNumber',
            'LedgerJournalTrans_ETGFairValueJournalNum',
            'LedgerJournalTrans_ETGAgreementno',
            'LedgerJournalTrans_ETGSalesAgreementno',
            'LedgerJournalTrans_ETG_Estimation',
            'LedgerJournalTrans_ETGLineestimationno',
            'LedgerJournalTrans_ETG_ActualID',
            'LedgerJournalTrans_ETGIntegrationContractNumber',
            'LedgerJournalTrans_ETGTERMONumber',
            'LedgerJournalTrans_ETGMotherTERMONumber',
            'LedgerJournalTrans_Grid_ReleaseDate',
            'LedgerJournalTrans_OffsetTxt'
        ];

        FormControl formControl;
        int         i;

        // Iterate through the list and hide/disable each control
        for (i = 1; i <= conLen(controlsToHide); i++)
        {
            formControl = this.design().controlName(conPeek(controlsToHide, i));

            if (formControl)
            {
                formControl.visible(false);
                formControl.enabled(false);
            }
        }
    }

}
